  ('social-worker-moex-06520', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體成員的問題之同質性考慮，何者正確：①採取最適距離法則，事先找到二到三個相同問題的案', '["治療性團體最好是問題同質性", "教育性團體要求資訊單一性", "任務性團體則以技巧、能力、知識、經驗越多元越理想", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06521', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '以下有關團體領導行為之角色，何者敘述錯誤？', '["廣為接納、支持其他團體成員的建立信賴者", "統整不同觀點，凝聚彼此關係的協調者", "溫馨鼓勵團體內的每位成員，友善回應團體成員的評鑑者", "指出團體有效運作過程困難來源的診斷者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06522', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於凝聚力對團體影響，下列敘述何者正確？①使成員願意傾聽  ②團體凝聚力高，可以滿足成員對親', '["正向和負向情緒的表達", "願意為團體的功能承擔責任  ⑤對團體的功能不會產生負 面影響", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06523', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體工作者催化團體過程的技巧，下列敘述何者正確？①應鼓勵成員對團體聚會內容有所貢獻，並小心', '["可以改善團體成員間的瞭解和建立開放的溝通管道", "協助團體成員面對重 要問題或任務時，表達其想法和感受，必要時重複摘述", "工作者使用回應技巧，以誘導足以影響團體 發展的特殊反應  ⑤工作者經由聚焦在特定的方向，以催化團體的過程", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06524', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社會工作者介入受壓族群的團體工作內容，下列敘述何者錯誤？', '["工作者提供受壓族群的團體服務設計，必須給有類似壓力的人參加", "團體形成任務中，工作者必須評量成員能力，藉此可以去除彼此間的障礙", "「去結構化」可以協助成員檢測自己的價值觀，並作批判性的評量", "評估團體歷程，工作者可聽取參加團體的受壓迫族群是否認為自己受到增權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06525', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體成員出現意見衝突是常見事件。Gosela Konopka 提出六種團體領導者解決衝突的方法，「任何一方 都沒得到充分的滿足，不過雙方都同意在自己的提案中加上限制」，此種描述比較符合下列那種方法？', '["征服（subjugation）", "退卻（withdrawal）", "妥協（compromise）", "多數原則（majority）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06526', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區工作者在與部落原住民工作的過程中，面對非主流的族群文化，應考慮各種面向，下列敘述何者錯 誤？', '["以規範性需求為導向，菁英專家意見才是社區重建的最佳實務", "試著了解性別、家族、少數族群的文化意涵和相互關係", "評估過程要尊重少數族群的聲音，並讓部落組織起來", "反省工作者本身的族群認同和文化對服務提供的意義"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06527', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '根據L. M. Siegel等人指出，常用的社區需求調查方法有八種，下列何者「不屬於」這些常見方法？', '["實驗法（Experiment design）", "社區公聽會（Community forums）", "德菲法（Delphi technique）", "社會與健康指標分析法（Social and health indicator analysis）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06528', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列有關臺灣地區社區營造、社區工作的辦理計畫與活動中，那一個項目的主管機關不是社會行政部門？', '["臺北市社區照顧關懷據點方案", "照顧服務社區化計畫", "臺北市社區互助方案", "社區營造創新實驗計畫"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06529', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '根據H. J. Rubin等人的理解，動員群眾是投入（involve）人民參與政治及社會活動的過程，下列何者 「不是」動員群眾的基本原則？', '["應掌握群眾參與的動機", "讓群眾看見參與能解決社區問題", "增加群眾參與社會運動付出的代價", "要懂得選取合適的社區事件"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
